function automatic [31:0] operation;
  input reg [3:0] rounds;
  input integer x;
  integer i;
  begin
    for (i = 0; i < rounds[3:0]; i = i + 1)
      x = x * 2;
    operation = x;
  end
endfunction

parameter A = 3;
wire a;
assign a = 2;
wire [31:0] x;
assign x = operation(A, a);
